def separate_paren_groups(paren_string: str) -> List[str]:
    paren_stack = []
    paren_groups = []
    for i in range(len(paren_string)):
        char = paren_string[i]
        if char == '(':
            paren_stack.append(char)
        elif char == ')':
            paren_stack.pop()
            if not paren_stack:
                paren_groups.append(paren_string[len(paren_stack):i + 1])
    return paren_groups

