def median(l: list):
    assert l != []
    assert type(l) == list
    assert type(l[0]) in {int, float}

    l.sort()
    size = len(l)
    middle = size // 2

    if size % 2 == 0:
        median = (l[middle] + l[middle - 1]) / 2
    else:
        median = l[middle]

    return median

