def sort_array(arr):
    def sort_array_helper(array, i):
        if i >= len(array):
            return []

        ones = sum(1 for n in array[i:] if (n & (1 << (i - 1))))
        ones_sorted = sort_array_helper(array, i + 1)
        zero_sorted = sort_array_helper(array, i + 1)

        ones_sorted.extend([array[i]] * ones)
        zero_sorted.extend([array[i]] * (len(array) - ones))

        ones_sorted.extend(zero_sorted)
        return ones_sorted

    return sort_array_helper(arr, 1)

