def is_nested(string):
    brackets = []
    for i in string:
        if i == ']':
            try:
                bracket = brackets.pop()
                if bracket == '[':
                    brackets.append(bracket)
            except IndexError:
                return False
        else:
            brackets.append(i)
    return False if brackets else True


